sql:
SELECT v.*, m.manufacturer_name
FROM vehicles v
JOIN manufacturers m ON v.make = m.manufacturer_name;

SELECT engine_id, engine_description, cylinders, displacement, horsepower, torque, fuel_type
FROM engine_types
WHERE horsepower > (
    SELECT AVG(horsepower) 
    FROM vehicles
);

SELECT vehicles.vehicle_id, vehicles.year, fuel_costs.fuel_cost_08 
FROM vehicles 
INNER JOIN fuel_costs ON vehicles.vehicle_id = fuel_costs.vehicle_id;

SELECT AVG(range) AS avg_range, AVG(city_mpg) AS avg_city_mpg, AVG(combined_mpg) AS avg_combined_mpg
FROM vehicles
WHERE make = 'Ford' AND year BETWEEN 2000 AND 2009;

SELECT vehicle_id, make, model, fuel_cost_08
FROM vehicles
WHERE fuel_cost_08 = (
    SELECT MAX(fuel_cost_08)
    FROM vehicles
);

